import React, { useEffect, useState } from 'react';
import api from '../../api/goodsApi';
import GoodsCard from '../../components/GoodsCard';
import './SearchPage.css'; // ✅ 여기에 CSS 파일 불러오기

function SearchPage() {
  const [keyword, setKeyword] = useState('');
  const [results, setResults] = useState([]);

  useEffect(() => {
    api.fetchGoods().then(res => {
      console.log("✅ 백엔드 응답 확인:", res.data); // 이 줄 추가
      setResults(res.data);
    });
  }, []);


  const filtered = results.filter(g => g.goods_name.includes(keyword));

  return (
    <div className="search-page">
      <input
        className="search-input"
        value={keyword}
        onChange={e => setKeyword(e.target.value)}
        placeholder="검색어 입력"
      />
      <div className="grid">
        {filtered.map(g => <GoodsCard key={g.goods_id} goods={g} />)}
      </div>
    </div>
  );
}

export default SearchPage;
